SELECT AVG(cases_count) AS average_cases_per_region
FROM disease_outbreaks
WHERE disease_id = 1;

SELECT COUNT(*)
FROM transmission_rates
WHERE rt_50 > (SELECT AVG(rt_50) FROM transmission_rates);

SELECT region_name, AVG(population) AS average_population
FROM regions
WHERE region_id BETWEEN 1 AND 10;

SELECT rt_50
FROM transmission_rates
WHERE rt_50 > 1.0;

SELECT COUNT(*)
FROM data_sources
WHERE reliability_score > 0.8;
